document.addEventListener("DOMContentLoaded", () => {
  const webp = () => {
    function testWebP(callback) {
      var webP = new Image();
      webP.onload = webP.onerror = function () {
        callback(webP.height == 2);
      };
      webP.src =
        "data:image/webp;base64,UklGRjoAAABXRUJQVlA4IC4AAACyAgCdASoCAAIALmk0mk0iIiIiIgBoSygABc6WWgAA/veff/0PP8bA//LwYAAA";
    }
    testWebP(function (support) {
      if (support === true) {
        document.querySelector("html").classList.add("_webp");
      } else {
        document.querySelector("html").classList.add("_no-webp");
      }
    });
  };
  webp();

  const map = document.getElementById("map");

  if (map) {
    const renderMap = async () => {
      const { mapName, indicatorName } = map.dataset;
      const indicatorBound = +map.dataset.indicatorBound;
      const mapZoom = +map.dataset.mapZoom;

      const getData = async () => {
        try {
          const data = await axios.get(`https://ecolab-sfy2q7apfq-lz.a.run.app/${mapName}/geojson`);
          return data.data;
        } catch (error) {
          console.log(error);
        }
      };
      const data = await getData();

      if (data.features.length === 0) return false;

      const mymap = L.map(map.id).setView([49.844435, 24.025543], mapZoom);

      const onFeatureClick = ({ properties }, layer) => {
        if (!properties) return false;

        const indicator = +properties[indicatorName];
        const street = properties["place"];

        const isIndicatorOk = indicator >= indicatorBound ? false : true;

        const className = isIndicatorOk
          ? "map-point__indicator_ok"
          : "map-point__indicator_bad";
        const infoAboutIndicatorState = isIndicatorOk
          ? mapName === "air"
            ? "Оксид вуглецю в нормі"
            : "Аміак в нормі"
          : `Це на ${Math.round(
              (indicator * 100) / indicatorBound - 100
            )}% вище норми`;

        let popupContent = `<div class="map-point__content"><p>Вміст ${indicatorName.toUpperCase()} на ${street}: <span class="map-point__indicator ${className}">${indicator} мг/м³</span> ${infoAboutIndicatorState}</p><p>Дата внесення змін: ${properties.periodDescription} ${properties.year} року</p></div>`;

        layer.bindPopup(popupContent);
      };

      L.tileLayer(
        "https://api.mapbox.com/styles/v1/{id}/tiles/{z}/{x}/{y}?access_token={accessToken}",
        {
          maxZoom: 18,
          id: "mapbox/streets-v11",
          tileSize: 512,
          zoomOffset: -1,
          accessToken:
            "pk.eyJ1IjoiZWNvbGFiIiwiYSI6ImNrdjN3ZWp3ZDA3a3Uydmx3OWxvY2tyb3kifQ.yjusFMzt8H0ASE5MqfcZ1A",
        }
      ).addTo(mymap);

      L.geoJSON(data, {
        onEachFeature: onFeatureClick,
        pointToLayer: function (feature, latlng) {
          return L.circleMarker(latlng, {
            radius: 13,
            fillColor: setFillColor(
              +feature.properties[indicatorName],
              indicatorBound
            ),
            fillOpacity: 1,
            color: "none",
            opacity: 1,
          });
        },
      }).addTo(mymap);

      function setFillColor(indicator, upperBound) {
        return indicator >= upperBound
          ? "rgb(216, 95, 56)"
          : "rgb(162, 208, 67)";
      }
    };
    renderMap();
  }
});
